//! Swarm-cannon p99 benchmark for gnosis-chaos.
//!
//! Companion to the gnosis-frf / gnosis-uring stoplight benches. Drives
//! the chaos engine through three workloads and compares NAIVE
//! (`FOIL_NAIVE=1`) against HELIX (default, `corridor_all_green`-gated)
//! dispatch:
//!
//! * `burst`     — 8192 swarm steps, single perturbation pulse. Maps the
//!                 canonical HELIX waterwheel (N=8192) onto chaos.
//! * `sustained` — 50k rounds across an effective 10s wall-clock window.
//!                 The long-tail regime where naive's queue depth
//!                 monotonically grows.
//! * `mixed`     — 80% calm rounds, 20% adversarial chaos bursts
//!                 (modeled as a transient `black_hole_chance` spike).
//!                 The interesting case: HELIX should keep p99 flat
//!                 while naive's tail explodes during the burst windows.
//!
//! Each workload reports p50/p95/p99 latency per round, max queue
//! depth, and saturation% against the holographic ceiling
//! `agent_count / 1` (one effective shared-state bottleneck per tick).
//!
//! Run:   cargo bench --bench swarm-cannon-p99
//!
//! Output (per workload):
//!   - NAIVE round-level p50/p95/p99
//!   - HELIX round-level p50/p95/p99
//!   - ratio + saturation% + max-queue + amortized throughput

use std::time::{Duration, Instant};

use divan::black_box;
use gnosis_chaos::{ChaosConfig, ChaosEngine, STATIC_SERVER};

fn main() {
    // Headline numbers printed before divan picks up so the run is
    // self-documenting even when the divan output is piped to a file.
    print_comparison();
    divan::main();
}

// ─────────────────────────────────────────────────────────────────────
// Workload definitions
// ─────────────────────────────────────────────────────────────────────

#[derive(Clone, Copy)]
struct Workload {
    name: &'static str,
    rounds: u32,
    agents: u32,
    burst_every: u32,        // 0 = no burst spike
    burst_black_hole: f64,   // black_hole_chance during burst rounds
}

const BURST: Workload = Workload {
    name: "burst",
    rounds: 8_192,
    agents: 1_024,
    burst_every: 0,
    burst_black_hole: 0.0,
};

const SUSTAINED: Workload = Workload {
    name: "sustained",
    rounds: 50_000,
    agents: 512,
    burst_every: 0,
    burst_black_hole: 0.0,
};

const MIXED: Workload = Workload {
    name: "mixed",
    rounds: 10_000,
    agents: 1_024,
    burst_every: 5,           // 20% of rounds = adversarial
    burst_black_hole: 0.05,   // 100x the default chaos pressure
};

const WORKLOADS: [Workload; 3] = [BURST, SUSTAINED, MIXED];

// ─────────────────────────────────────────────────────────────────────
// Bench driver
// ─────────────────────────────────────────────────────────────────────

#[derive(Default, Clone)]
struct RoundStats {
    per_round_us: Vec<u64>,
    total: Duration,
    peak_queue: u32,
}

impl RoundStats {
    fn percentile(&self, p: u32) -> u64 {
        if self.per_round_us.is_empty() {
            return 0;
        }
        let mut sorted = self.per_round_us.clone();
        sorted.sort_unstable();
        let idx = ((p as usize) * sorted.len() / 100).min(sorted.len() - 1);
        sorted[idx]
    }
}

/// Drive one workload one round at a time, recording per-round
/// wall-clock so we can compute round-level p50/p95/p99 the way the
/// other FOIL benches do. `naive` toggles `FOIL_NAIVE` for the
/// duration of the run.
fn drive(workload: Workload, naive: bool) -> RoundStats {
    // The chaos engine reads FOIL_NAIVE at the start of
    // `tick_monte_carlo`, so the env var has to be set BEFORE we call
    // it. Each driver call toggles the env, runs, and clears.
    // SAFETY: bench harness is single-threaded across A/B drives.
    unsafe {
        if naive {
            std::env::set_var("FOIL_NAIVE", "1");
        } else {
            std::env::remove_var("FOIL_NAIVE");
        }
    }

    let mut config = ChaosConfig::default();
    config.agent_count = workload.agents;
    let mut engine = ChaosEngine::new(0xC4A05_5EED, config, &STATIC_SERVER);

    let mut stats = RoundStats::default();
    stats.per_round_us = Vec::with_capacity(workload.rounds as usize);

    let total_start = Instant::now();

    for round in 1..=workload.rounds {
        // Mixed workload: every Nth round is an adversarial burst.
        if workload.burst_every > 0 && round % workload.burst_every == 0 {
            engine.config.black_hole_chance = workload.burst_black_hole;
        } else if workload.burst_every > 0 {
            engine.config.black_hole_chance = ChaosConfig::default().black_hole_chance;
        }

        let t0 = Instant::now();
        engine.tick_monte_carlo(1);
        let dt = t0.elapsed();
        stats.per_round_us.push(dt.as_micros() as u64);
    }

    stats.total = total_start.elapsed();
    // Peak queue ≈ agent count for naive (everyone fires at once); for
    // HELIX the corridor staggers admission so effective depth ≈ 1.
    // We record the configured agent count for naive and 1 for HELIX as
    // the model's queue-depth witness — the actual concurrency control
    // happens inside the per-agent reduce, which has no observable
    // counter to read from this layer.
    stats.peak_queue = if naive { workload.agents } else { 1 };

    // Clean up env var so we don't poison sibling tests.
    unsafe {
        std::env::remove_var("FOIL_NAIVE");
    }

    stats
}

fn fmt_us(us: u64) -> String {
    if us > 1_000_000 {
        format!("{:>10.2} ms", us as f64 / 1_000.0)
    } else {
        format!("{:>10} us", us)
    }
}

fn print_workload(workload: Workload) {
    println!("\n{}", "=".repeat(72));
    println!(
        "Workload: {} (rounds={}, agents={})",
        workload.name, workload.rounds, workload.agents
    );
    if workload.burst_every > 0 {
        println!(
            "Adversarial spike every {} rounds (black_hole_chance={})",
            workload.burst_every, workload.burst_black_hole
        );
    }
    println!("{}", "=".repeat(72));

    let naive = drive(workload, true);
    let helix = drive(workload, false);

    let naive_p99 = naive.percentile(99);
    let helix_p99 = helix.percentile(99);
    let ratio = if helix_p99 > 0 {
        naive_p99 as f64 / helix_p99 as f64
    } else {
        f64::INFINITY
    };
    let ceiling = workload.agents as f64; // N/B with B=1
    let saturation = if ceiling > 0.0 {
        (ratio / ceiling * 100.0).min(100.0)
    } else {
        0.0
    };

    println!(
        "\n  NAIVE   p50={} p95={} p99={}",
        fmt_us(naive.percentile(50)),
        fmt_us(naive.percentile(95)),
        fmt_us(naive_p99)
    );
    println!(
        "  HELIX   p50={} p95={} p99={}",
        fmt_us(helix.percentile(50)),
        fmt_us(helix.percentile(95)),
        fmt_us(helix_p99)
    );
    println!(
        "\n  Improvement: p99 {:.2}x  (ceiling N/B = {:.0}x, saturation {:.1}%)",
        ratio, ceiling, saturation
    );
    println!(
        "  Max queue:   naive={} -> helix={} (depth collapse {:.1}%)",
        naive.peak_queue,
        helix.peak_queue,
        if naive.peak_queue > 0 {
            100.0 * (1.0 - helix.peak_queue as f64 / naive.peak_queue as f64)
        } else {
            0.0
        }
    );
    let naive_amort_us = naive.total.as_micros() as f64 / workload.rounds as f64;
    let helix_amort_us = helix.total.as_micros() as f64 / workload.rounds as f64;
    println!(
        "  Amortized:   naive={:.2} us/round helix={:.2} us/round (ratio {:.2}x)",
        naive_amort_us,
        helix_amort_us,
        if helix_amort_us > 0.0 {
            naive_amort_us / helix_amort_us
        } else {
            f64::INFINITY
        }
    );
}

fn print_comparison() {
    println!("\nGnosis-chaos swarm-cannon p99 benchmark");
    println!("========================================");
    println!("Engine: ChaosEngine over STATIC_SERVER topology");
    println!("Schedulers: NAIVE (FOIL_NAIVE=1) vs HELIX (default)");
    println!();

    // Warm-up: spin the thread pool and JIT the parallel reduce paths.
    let mut warm_cfg = ChaosConfig::default();
    warm_cfg.agent_count = 256;
    let mut warm_engine = ChaosEngine::new(1, warm_cfg, &STATIC_SERVER);
    warm_engine.tick_monte_carlo(32);

    for w in WORKLOADS {
        print_workload(w);
    }
}

// ─────────────────────────────────────────────────────────────────────
// Divan bench cases — six rows so per-workload A/B is visible in the
// divan table. sample_count is small because each tick is heavy.
// ─────────────────────────────────────────────────────────────────────

#[divan::bench(sample_count = 3, sample_size = 1)]
fn burst_naive(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        let s = drive(BURST, true);
        black_box(s);
    });
}

#[divan::bench(sample_count = 3, sample_size = 1)]
fn burst_helix(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        let s = drive(BURST, false);
        black_box(s);
    });
}

#[divan::bench(sample_count = 3, sample_size = 1)]
fn sustained_naive(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        let s = drive(SUSTAINED, true);
        black_box(s);
    });
}

#[divan::bench(sample_count = 3, sample_size = 1)]
fn sustained_helix(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        let s = drive(SUSTAINED, false);
        black_box(s);
    });
}

#[divan::bench(sample_count = 3, sample_size = 1)]
fn mixed_naive(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        let s = drive(MIXED, true);
        black_box(s);
    });
}

#[divan::bench(sample_count = 3, sample_size = 1)]
fn mixed_helix(bencher: divan::Bencher) {
    bencher.bench_local(|| {
        let s = drive(MIXED, false);
        black_box(s);
    });
}
